/*NOT USED ONLY VIEWING PURPOSES*/ 

CREATE TABLE IF NOT EXISTS "project" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"date-start" DATE,
	"date-end" DATE,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "task" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"status" VARCHAR(255),
	"time-start" TIMETZ,
	"time-end" TIMETZ,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "comment" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"text" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "compte" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"name" VARCHAR(255),
	"mail" VARCHAR(255),
	"password" VARCHAR(255),
	"role" VARCHAR(255),
	PRIMARY KEY("id")
);


CREATE INDEX "compte_index_0"
ON "compte" ();

CREATE TABLE IF NOT EXISTS "responsability" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "livrable" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"source" VARCHAR(255),
	PRIMARY KEY("id")
);



ALTER TABLE "compte"
ADD FOREIGN KEY("id") REFERENCES "project"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "project"
ADD FOREIGN KEY("id") REFERENCES "task"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "comment"
ADD FOREIGN KEY("id") REFERENCES "project"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "comment"
ADD FOREIGN KEY("id") REFERENCES "task"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "compte"
ADD FOREIGN KEY("id") REFERENCES "responsability"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "task"
ADD FOREIGN KEY("id") REFERENCES "responsability"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "livrable"
ADD FOREIGN KEY("id") REFERENCES "project"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;